import { HashRouter, Routes, Route } from "react-router-dom"; 
import './App.css';
import { ToastContainer } from 'react-toastify';

import DriverProvider from './context/DriverContext';


function App() {
  return (
    <HashRouter> 
    <div className="screen">
      <SeasonProvider>
        <LoginProvider >
        <Menu />
        <main className="info">
          <Routes>
            <Route path="/" element={ 
              <Home></Home>
            } />
            <Route path="/login" element={
              <Login></Login>
            } />
            <Route path="/pilots" element={
              <DriverProvider>  
                <Driver></Driver>
                <Table type={"drivers"}></Table>
              </DriverProvider>
            } />
            <Route path="/teams" element={
              <TeamProvider>
                <Table type={"teams"}></Table>
              </TeamProvider>
            } />
            <Route path="/races" element={
              <RaceProvider>
                <Races></Races>
              </RaceProvider>
            } />
            <Route path="/editpilots" element={
              <Private>
                <EditProvider type={"pilotos"}>
                  <TableEdit type={"drivers"}></TableEdit>
                </EditProvider>
              </Private>
            } />
            <Route path="/editteams" element={
              <Private>
                <EditProvider type={"equipes"}>
                  <TableEdit type={"drivers"}></TableEdit>
                </EditProvider>
              </Private>
            } />
            <Route path="/create" element={
              <Private>
                <div className="createForms">
                <FormCreateDriver></FormCreateDriver>
                <FormCreateTeam></FormCreateTeam>
                <FormCreateRace></FormCreateRace>
                </div>
              </Private>
            } />
          </Routes>
        </main>
        </LoginProvider>
      </SeasonProvider>
    </div>
    <ToastContainer />
    </HashRouter>
  );
}

export default App;
